import { Component, OnInit, OnDestroy } from '@angular/core';
import { Router } from '@angular/router';
import { HttpClient, HttpParams } from '@angular/common/http';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-hr-dashboard',
  template: `
  <div class="page">
    <div class="page-header">
      <h1 class="page-title">HR Dashboard</h1>
      <button class="btn btn-black" (click)="logout()">Logout</button>
    </div>

    <div class="app-card" style="max-width:720px;margin-bottom:18px">
      <h2>Post New Internship</h2>
      <input class="form-control" placeholder="Title" [(ngModel)]="title" />
      <input class="form-control" placeholder="Location" [(ngModel)]="location" />
      <input class="form-control" placeholder="CTC" [(ngModel)]="ctc" />
      <input class="form-control" placeholder="Company Name" [(ngModel)]="companyName" />
      <textarea class="form-control" placeholder="Description" [(ngModel)]="description"></textarea>
      <input type="file" (change)="onPdfSelected($event)" (focus)="pausePolling()" (blur)="resumePolling()" style="margin-bottom:10px" />
      <div class="card-actions">
        <button (click)="handlePdfUpload()" class="btn">Upload PDF</button>
        <button *ngIf="pdfUploaded" (click)="handlePost()" class="btn">Post Internship</button>
      </div>
    </div>

    <h2>Posted Internships</h2>
    <div class="card-grid">
      <div *ngFor="let i of internships" class="card-item">
        <h3>{{i.title}}</h3>
        <p><b>Company:</b> {{i.companyName}}</p>
        <p><b>Place:</b> {{i.location}}</p>
        <p><b>CTC:</b> {{i.ctc}}</p>
        <p><b>Description:</b> {{i.description}}</p>
        <div class="card-actions"><button class="btn btn-ghost" (click)="handleDelete(i.id)">Delete</button></div>
      </div>
    </div>

    <h2 style="margin-top:20px">Candidates</h2>
    <div *ngFor="let app of applications" class="card-item" style="margin-bottom:14px">
      <div style="display:flex;justify-content:space-between;align-items:center">
        <h3 style="margin:0">{{app.candidateName}}</h3>
        <button class="btn" (click)="selectedCandidate = app">View Details</button>
      </div>

      <div style="padding-left:15px">
        <p>Test Cleared</p>

        <!-- Show scheduled interview details (L1/L2/HR) similar to React frontend -->
        <div *ngIf="app.l1Date || app.l2Date || app.l1Mode || app.l2Mode || app.hrDate || app.hrMode">
            <!-- L1 status: if requested show waiting message, otherwise show scheduled details -->
            <p *ngIf="app.interviewStatus === 'L1_SCHEDULED' && app.l1InterviewerStatus === 'REQUESTED'">L1 scheduled – waiting for interviewer response</p>
            <p *ngIf="!(app.interviewStatus === 'L1_SCHEDULED' && app.l1InterviewerStatus === 'REQUESTED') && app.l1Date">L1 – {{ formatDate(app.l1Date) }} | {{ getInterviewerName(app.l1InterviewerId) }} | {{ app.l1Mode }}</p>
            <p *ngIf="app.l1Result"><b>L1 Result:</b> {{ app.l1Result }}</p>

            <!-- L2 status -->
            <p *ngIf="app.interviewStatus === 'L2_SCHEDULED' && app.l2InterviewerStatus === 'REQUESTED'">L2 scheduled – waiting for interviewer response</p>
            <p *ngIf="!(app.interviewStatus === 'L2_SCHEDULED' && app.l2InterviewerStatus === 'REQUESTED') && app.l2Date">L2 – {{ formatDate(app.l2Date) }} | {{ getInterviewerName(app.l2InterviewerId) }} | {{ app.l2Mode }}</p>
            <p *ngIf="app.l2Result"><b>L2 Result:</b> {{ app.l2Result }}</p>

            <!-- HR result shown immediately below L2 result -->
            <div *ngIf="app.hrResult">
              <p><b>HR Result:</b> {{ app.hrResult }}</p>
            </div>

            <!-- HR status -->
            <p *ngIf="app.interviewStatus === 'HR_SCHEDULED'">HR Interview Scheduled<br/>
              <b>Date:</b> {{ formatDate(app.hrDate) }}<br/>
              <b>Time:</b> {{ formatTime(app.hrTime) }}<br/>
              <b>Mode:</b> {{ app.hrMode }}
            </p>
        </div>

        <div *ngIf="app.signedOfferLetter">
          <p style="font-weight:600;color:black">Offer Letter-- Sent</p>
        </div>

        <div *ngIf="app.signedOfferLetter">
          <a [href]="'http://localhost:8080/signed-offers/' + app.signedOfferLetter" target="_blank">View Signed Offer Letter</a>
        </div>

        <div *ngIf="app.signedOfferLetter">
          <ng-container *ngIf="getOnboardingRecord(app)">
            <p><b>Onboarding Status:</b>
              <span [style.color]="statusColor(getOnboardingRecord(app).status)" style="font-weight:600">{{ getOnboardingRecord(app).status }}</span>
            </p>

            <button *ngIf="getOnboardingRecord(app)" (click)="router.navigate(['/hr/onboarding', app.email])" style="padding:6px 12px;background:black;color:white;border:none;border-radius:6px;cursor:pointer;margin-right:10px">View Onboarding Details</button>

            <button *ngIf="getOnboardingRecord(app) && getOnboardingRecord(app).status === 'VERIFIED' && !employeeExists(app.email)" (click)="router.navigate(['/hr/create-employee', app.email])" style="padding:6px 12px;background:#16a34a;color:white;border:none;border-radius:6px;cursor:pointer">Create Employee Profile</button>

            <button *ngIf="employeeExists(app.email)" (click)="router.navigate(['/hr/employee', app.email])" style="padding:6px 12px;background:black;color:white;border:none;border-radius:6px;cursor:pointer">View Employee Details</button>
          </ng-container>

          <!-- Onboarding is filled by the candidate after they upload a signed offer; HR views onboarding records via the details link above. -->
        </div>

      </div>

      <div *ngIf="app.interviewStatus === 'HR_SCHEDULED' && app.status !== 'SELECTED' && app.status !== 'REJECTED'" class="card-actions">
        <button (click)="updateHrResult(app.id, 'HR_PASSED')" class="btn success">Select</button>
        <button (click)="updateHrResult(app.id, 'HR_FAILED')" class="btn danger">Reject</button>
      </div>

      <div *ngIf="(app.status === 'SELECTED' || app.status === 'OFFER_PENDING' || app.status === 'OFFER_SENT') && !app.offerLetterFile">
        <input type="file" accept=".pdf,application/pdf" (change)="handleOfferFileChange(app.id, $event)" (focus)="pausePolling()" />
        <button (click)="uploadOfferLetter(app.id)" class="btn" style="margin-left:8px">Upload Offer Letter</button>
        <span *ngIf="uploadedOfferForApp[app.id]" style="margin-left:12px;color:var(--success)">Uploaded: {{ uploadedOfferForApp[app.id] }}</span>
        <span *ngIf="offerFiles[app.id]" style="margin-left:12px">Selected: {{ offerFiles[app.id].name }}</span>
        <div *ngIf="lastUploadDebug && lastUploadDebug.url && lastUploadDebug.url.includes(app.id)" style="margin-top:8px;background:var(--bg);padding:8px;border-radius:6px;border:1px solid rgba(15,23,42,0.04)">
          <div style="font-size:12px;color:var(--text)"><b>Last upload debug</b></div>
          <div style="font-size:12px;margin-top:4px">URL: {{ lastUploadDebug.url }}</div>
          <div style="font-size:12px">Status: {{ lastUploadDebug.status }}</div>
          <div style="font-size:12px">Body: <span style="color:var(--success)">{{ lastUploadDebug.body }}</span></div>
        </div>
      </div>

        <div *ngIf="showScheduleOptions(app)">
          <input type="date" [ngModel]="getScheduleValue(app.id,'date')" (ngModelChange)="setScheduleValue(app.id,'date',$event)" />
          <input type="time" [ngModel]="getScheduleValue(app.id,'time')" (ngModelChange)="setScheduleValue(app.id,'time',$event)" />
          <select [ngModel]="getScheduleValue(app.id,'mode')" (ngModelChange)="setScheduleValue(app.id,'mode',$event)">
            <option value="">Mode</option>
            <option value="ONLINE">Online</option>
            <option value="OFFLINE">Offline</option>
          </select>
          <select *ngIf="app.status !== 'HR_PENDING'" [ngModel]="getScheduleValue(app.id,'interviewerId')" (ngModelChange)="setScheduleValue(app.id,'interviewerId',$event)">
            <option value="">Interviewer</option>
            <option *ngFor="let iv of interviewerOptionsForApp(app)" [value]="iv.id">{{ iv.name }}</option>
          </select>
          <button (click)="scheduleInterview(app.id, app.status)">{{ scheduleLabel(app) }}</button>
        </div>

        <!-- HR result display (mirror candidate view) -->
        <div *ngIf="app.hrResult">
          <p><b>HR Result:</b> {{ app.hrResult }}</p>
        </div>

      <hr />
    </div>

    <div *ngIf="selectedCandidate" class="side-panel">
      <h3>Candidate Details</h3>
      <p><b>Name:</b> {{selectedCandidate.candidateName}}</p>
      <p><b>Email:</b> {{selectedCandidate.email}}</p>
      <p><b>Phone:</b> {{selectedCandidate.phone}}</p>
      <p><b>Degree:</b> {{selectedCandidate.degree}}</p>
      <p><b>College:</b> {{selectedCandidate.college}}</p>
      <p><b>CGPA:</b> {{selectedCandidate.cgpa}}</p>
      <p><b>Skills:</b> {{selectedCandidate.skills}}</p>
      <a [href]="'http://localhost:8080/resumes/' + selectedCandidate.resumeFileName" target="_blank">Download Resume</a>
      <br/><br/>
      <button class="btn" (click)="selectedCandidate=null">Close</button>
    </div>
  </div>
  `
})
export class HrDashboardComponent implements OnInit, OnDestroy {
  title = '';
  location = '';
  ctc = '';
  description = '';
  companyName = '';

  internships: any[] = [];
  applications: any[] = [];
  interviewerList: any[] = [];
  scheduleData: any = {};
  selectedCandidate: any = null;
  offerFiles: any = {};
  uploadedOfferForApp: Record<string,string> = {};
  lastUploadDebug: { url: string; status: string; body: any } | null = null;
  onboardingForms: Record<string, any> = {};

  pdfFile: any = null;
  uploadedFileName = '';
  pdfUploaded = false;
  onboardingList: any[] = [];
  employeeList: any[] = [];

  private intervalId: any;
  private pollingPaused = false;

  constructor(public auth: AuthService, private http: HttpClient, public router: Router) {}

  ngOnInit() {
    if (!this.auth.user || this.auth.user.role !== 'HR') {
      this.router.navigate(['/']);
      return;
    }

    this.fetchAll();
    this.startPolling();
  }

  ngOnDestroy() {
    this.stopPolling();
  }

  startPolling() {
    this.stopPolling();
    this.intervalId = setInterval(() => { if (!this.pollingPaused) this.fetchAll(); }, 5000);
  }

  stopPolling() { if (this.intervalId) { clearInterval(this.intervalId); this.intervalId = null; } }

  pausePolling() { this.pollingPaused = true; }

  resumePolling() { this.pollingPaused = false; }

  logout() {
    this.auth.logout();
    this.router.navigate(['/']);
  }

  private fetchAll() {
    const y = window.scrollY || 0;
    // perform all fetches in parallel and restore scroll after
    Promise.all([
      this.fetchInternships(),
      this.fetchApplications(),
      this.fetchOnboarding(),
      this.fetchEmployees()
    ]).finally(() => { setTimeout(() => window.scrollTo(0, y), 0); });
  }

  formatDate(dateString: any) {
    if (!dateString) return '';
    return new Date(dateString).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
  }

  formatTime(time: string) {
    if (!time) return '';
    const [h, m] = time.split(':');
    const d = new Date(); d.setHours(Number(h), Number(m));
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }

  getInterviewerName(id: number) {
    if (!id) return '';
    // Prefer lookups from fetched employee list
    const emp = this.employeeList && this.employeeList.find(e => (e.id ?? e.interviewerId ?? e.employeeId) === id);
    if (emp) return emp.name ?? emp.fullName ?? emp.interviewerName ?? emp.email ?? '';
    // Fallback to small hardcoded mapping for legacy ids
    return id === 1 ? 'Kavya' : id === 2 ? 'Arun' : id === 3 ? 'Divya' : '';
  }

  async fetchOnboarding() {
    try {
      const res: any = await this.http.get('http://localhost:8080/api/onboarding').toPromise();
      this.onboardingList = res || [];
    } catch (err) { console.error(err); }
  }

  async fetchInternships() {
    try { this.internships = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise(); } catch (err) { console.error(err); }
  }

  async fetchApplications() {
    try { this.applications = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise(); } catch (err) { console.error(err); }
  }

  handleOfferFileChange(id: any, event: any) {
    const file = event.target.files?.[0];
    if (!file) return;
    // accept files that are PDF by MIME or by filename extension to handle browser differences
    const isPdfMime = file.type && file.type.toLowerCase().includes('pdf');
    const isPdfExt = file.name && file.name.toLowerCase().endsWith('.pdf');
    if (!isPdfMime && !isPdfExt) {
      alert('Please select a PDF file for the offer letter');
      return;
    }
    // store selected file; do not auto-upload — user clicks Upload
    this.offerFiles = { ...this.offerFiles, [id]: file };
  }
  async uploadOfferLetter(id: any) {
    const file = this.offerFiles[id];
    if (!file) return alert('Select offer letter');
    // pause polling and preserve scroll to avoid UI jumps during upload
    this.pausePolling();
    const y = window.scrollY || 0;
    try {
      const base = 'http://localhost:8080/api/applications/upload-offer-letter';
      const tryFieldNames = ['file', 'offerLetter', 'offer', 'offerFile'];
      let success = false;
      let lastErr: any = null;

      for (const fieldName of tryFieldNames) {
        // try path endpoint
        const pathUrl = `${base}/${encodeURIComponent(id)}`;
        const formPath = new FormData();
        formPath.append(fieldName, file);
        formPath.append('applicationId', id);
        try {
          const body = await this.http.post(pathUrl, formPath, { responseType: 'text' }).toPromise();
          this.lastUploadDebug = { url: pathUrl, status: 'OK', body: `field:${fieldName} => ${body}` };
          if (typeof body === 'string' && body.trim()) this.uploadedOfferForApp[id] = body;
          success = true; break;
        } catch (errPath) { lastErr = errPath; }

        // try query endpoint
        const queryUrl = `${base}?applicationId=${encodeURIComponent(id)}`;
        const formQuery = new FormData();
        formQuery.append(fieldName, file);
        formQuery.append('applicationId', id);
        try {
          const body2 = await this.http.post(queryUrl, formQuery, { responseType: 'text' }).toPromise();
          this.lastUploadDebug = { url: queryUrl, status: 'OK', body: `field:${fieldName} => ${body2}` };
          if (typeof body2 === 'string' && body2.trim()) this.uploadedOfferForApp[id] = body2;
          success = true; break;
        } catch (errQuery) { lastErr = errQuery; }
      }

      if (!success) {
        console.error('Offer upload failed for all attempts', lastErr);
        this.lastUploadDebug = { url: base, status: 'FAILED', body: String(lastErr) };
        alert('Error uploading offer letter — see debug box for details');
        throw lastErr;
      }

      // refresh applications after successful upload
      await this.fetchApplications();
      alert('Offer uploaded (check response)');
    } finally {
      setTimeout(() => window.scrollTo(0, y), 0);
      this.resumePolling();
    }
  }

  async updateOnboardingStatus(id: any, status: string) {
    await this.http.put(`http://localhost:8080/api/onboarding/update/${id}/${status}`, {}).toPromise();
    this.fetchOnboarding();
  }

  openOnboardingForm(appId: any, email: string) {
    this.onboardingForms = { ...this.onboardingForms, [appId]: { address: '', aadhaar: '', pan: '', bankAccount: '', email, applicationId: appId } };
    // pause polling while HR fills the form
    this.pausePolling();
  }

  cancelOnboardingForm(appId: any) {
    const copy = { ...this.onboardingForms };
    delete copy[appId];
    this.onboardingForms = copy;
    this.resumePolling();
  }

  async submitOnboarding(appId: any) {
    const payload = this.onboardingForms[appId];
    if (!payload) return;
    if (!payload.address || !payload.aadhaar || !payload.pan || !payload.bankAccount) return alert('Fill all fields');
    try {
      await this.http.post('http://localhost:8080/api/onboarding', payload).toPromise();
      alert('Onboarding details saved');
      // refresh lists so candidate sees changes
      await this.fetchAll();
      this.cancelOnboardingForm(appId);
    } catch (err) { console.error(err); alert('Error saving onboarding'); }
  }

  onPdfSelected(e: any) { this.pdfFile = e.target.files?.[0]; }

  async handlePdfUpload() {
    if (!this.pdfFile) return alert('Select PDF');
    try {
      const form = new FormData();
      form.append('file', this.pdfFile);
      // backend returns plain text (filename) with 200 OK — ask for text to avoid JSON parse error
      const res = await this.http.post('http://localhost:8080/api/internships/upload-pdf', form, { responseType: 'text' }).toPromise();
      this.uploadedFileName = res as string;
      this.pdfUploaded = true;
    } catch (err) {
      console.error('PDF upload failed', err);
      alert('Error uploading PDF');
    }
  }

  async handlePost() {
    if (!this.pdfUploaded) return alert('Upload PDF first');
    const form = new FormData();
    form.append('companyName', this.companyName);
    form.append('title', this.title);
    form.append('location', this.location);
    form.append('ctc', this.ctc);
    form.append('description', this.description);
    form.append('pdfFileName', this.uploadedFileName);
    await this.http.post('http://localhost:8080/api/internships/post', form).toPromise();
    this.companyName = this.title = this.location = this.ctc = this.description = '';
    this.pdfUploaded = false; this.pdfFile = null; this.fetchInternships();
  }

  async handleDelete(id: any) { await this.http.delete(`http://localhost:8080/api/internships/${id}`).toPromise(); this.fetchInternships(); }

  handleInputChange(appId: any, field: string, value: any) {
    this.scheduleData = { ...this.scheduleData, [appId]: { ...(this.scheduleData[appId] || {}), [field]: value } };
  }

  // Helpers for template ngModel bindings so inputs persist while app re-fetches
  getScheduleValue(appId: any, field: string) {
    return (this.scheduleData[appId] && this.scheduleData[appId][field]) || '';
  }

  setScheduleValue(appId: any, field: string, value: any) {
    this.scheduleData = { ...this.scheduleData, [appId]: { ...(this.scheduleData[appId] || {}), [field]: value } };
  }

  async scheduleInterview(appId: any, status: any) {
    const data = this.scheduleData[appId];
    if (!data?.date || !data?.time || !data?.mode) { return alert('Fill all fields'); }
    // pause polling and preserve scroll while scheduling to avoid UI jumps
    this.pausePolling();
    const y = window.scrollY || 0;
    const params = new HttpParams()
      .set('applicationId', appId)
      .set('level', status === 'TEST_PASSED' ? 'L1' : status === 'L2_PENDING' ? 'L2' : 'HR')
      .set('date', data.date)
      .set('time', data.time)
      .set('mode', data.mode)
      .set('interviewerId', data.interviewerId || '');
    try {
      await this.http.post('http://localhost:8080/api/applications/schedule-interview', null, { params, responseType: 'text' }).toPromise();
      await this.fetchApplications();
    } catch (err) { console.error('Schedule interview failed', err); alert('Error scheduling interview'); }
    finally {
      setTimeout(() => window.scrollTo(0, y), 0);
      this.resumePolling();
    }
  }

  async fetchEmployees() { try { this.employeeList = await this.http.get<any[]>('http://localhost:8080/api/employees').toPromise(); } catch (err) { console.error(err); } }

  // Build interviewer options from employee list or fallback to hardcoded list
  interviewerOptionsForApp(app: any) {
    const fallback = [{ id: 1, name: 'Kavya' }, { id: 2, name: 'Arun' }, { id: 3, name: 'Divya' }];
    if (!this.employeeList || !this.employeeList.length) return fallback.filter(iv => iv.id !== app.l1InterviewerId);

    // Filter employees to those likely to be interviewers and exclude the current HR user
    const candidates = this.employeeList.filter(e => {
      const role = (e.role || e.designation || '') as string;
      const roleIsInterviewer = role && role.toLowerCase().includes('interviewer');
      const flagInterviewer = e.isInterviewer === true || e.interviewer === true || !!e.interviewerId;
      const notSelf = !(this.auth.user && this.auth.user.email && this.auth.user.email === e.email);
      return (roleIsInterviewer || flagInterviewer) && notSelf;
    });

    const list = candidates.map(e => ({ id: e.id ?? e.interviewerId ?? e.employeeId, name: e.name ?? e.fullName ?? e.interviewerName ?? e.email }));
    // If after filtering we have no candidates, fallback to hardcoded list
    if (!list.length) return fallback.filter(iv => iv.id !== app.l1InterviewerId);
    return list.filter(iv => iv.id !== app.l1InterviewerId);
  }

  async updateHrResult(id: any, result: string) {
    // preserve scroll and pause polling while updating
    this.pausePolling();
    const y = window.scrollY || 0;
    try {
      // optimistic local update so UI reflects change quickly
      const localApp = this.applications.find(a => a.id === id);
      if (localApp) {
        localApp.status = (result === 'HR_PASSED') ? 'SELECTED' : (result === 'HR_FAILED' ? 'REJECTED' : localApp.status);
        // also set hrResult for immediate UI feedback (backend may use PASSED/FAILED)
        localApp.hrResult = (result === 'HR_PASSED') ? 'PASSED' : (result === 'HR_FAILED' ? 'FAILED' : localApp.hrResult);
      }

      // try params approach first
      await this.http.post('http://localhost:8080/api/applications/hr-result', null, { params: new HttpParams().set('applicationId', id).set('result', result), responseType: 'text' }).toPromise();
      await this.fetchAll();
    } catch (errParams) {
      console.warn('hr-result(params) failed, trying JSON body', errParams);
      try {
        // fallback to JSON body if params approach fails
        await this.http.post('http://localhost:8080/api/applications/hr-result', { applicationId: id, result }, { responseType: 'text' }).toPromise();
        await this.fetchAll();
      } catch (errBody) {
        console.error('Failed to update HR result with both params and body', errBody);
        alert('Error updating HR result');
      }
    }
    finally {
      setTimeout(() => window.scrollTo(0, y), 0);
      this.resumePolling();
    }
  }

  getOnboardingRecord(app: any) {
    return this.onboardingList.filter(ob => ob.applicationId === app.id).slice(-1)[0];
  }

  statusColor(status: string) {
    if (!status) return '#9ca3af';
    return status === 'VERIFIED' ? 'green' : status === 'REJECTED' ? 'red' : 'orange';
  }

  employeeExists(email: string) { return !!this.employeeList.find(emp => emp.email === email); }

  showScheduleOptions(app: any) {
    return (app.status === 'TEST_PASSED' && app.interviewStatus !== 'L1_SCHEDULED') ||
      (app.status === 'L2_PENDING' && app.interviewStatus !== 'L2_SCHEDULED') ||
      (app.status === 'HR_PENDING' && app.interviewStatus !== 'HR_SCHEDULED') ||
      app.l1InterviewerStatus === 'REJECTED' || app.l2InterviewerStatus === 'REJECTED';
  }

  scheduleLabel(app: any) {
    return app.status === 'TEST_PASSED' ? 'Schedule L1' : app.status === 'L2_PENDING' ? 'Schedule L2' : 'Schedule HR';
  }
}
